/**
 * Find ordered intermediate stations between two station codes.
 * Returns station codes in order from `from` to `to` (exclusive of endpoints),
 * or an empty array if no route connects them.
 */
export function getIntermediateStations(from: string, to: string, dataSource?: TransitSystem): string[] {
  const candidates = dataSource ? ROUTES.filter((r) => r.dataSource === dataSource) : ROUTES;
  for (const route of candidates) {
    const fromIdx = route.stations.indexOf(from);
    const toIdx = route.stations.indexOf(to);
    if (fromIdx === -1 || toIdx === -1) continue;
    const start = Math.min(fromIdx, toIdx);
    const end = Math.max(fromIdx, toIdx);
    if (end - start <= 1) return []; // adjacent stations
    const intermediates = route.stations.slice(start + 1, end);
    return fromIdx < toIdx ? intermediates : [...intermediates].reverse();
  }
  return [];
}
